/**
 * A single Server-Sent Event message.
 *
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * The `Content-Type` used for SSE responses.
 *
 * @since 1.0.0
 * @category constants
 */
export const contentType = "text/event-stream"

/**
 * Format a `SSEMessage` into its SSE wire representation. Multi-line `data` is
 * split into multiple `data:` fields as required by the spec.
 *
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (message: SSEMessage): string => {
  let out = ""
  if (message.event !== undefined) {
    out += `event: ${message.event}\n`
  }
  if (message.id !== undefined) {
    out += `id: ${message.id}\n`
  }
  if (message.retry !== undefined) {
    out += `retry: ${message.retry}\n`
  }
  const data = message.data
  if (data.length === 0) {
    out += "data: \n"
  } else {
    const lines = data.split("\n")
    for (let i = 0; i < lines.length; i++) {
      out += `data: ${lines[i]}\n`
    }
  }
  return out + "\n"
}

/**
 * JSON-encode any value and format it as a data-only SSE message.
 *
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

/**
 * An encoder turns a value into a formatted SSE wire message.
 *
 * @since 1.0.0
 * @category models
 */
export interface EventEncoder<A, R> {
  (value: A): Effect.Effect<string, ParseError, R>
}

/**
 * A decoder turns a decoded SSE message into a typed value.
 *
 * @since 1.0.0
 * @category models
 */
export interface EventDecoder<A, R> {
  (message: SSEMessage): Effect.Effect<A, ParseError, R>
}

const unwrapAST = (ast: AST.AST): AST.AST => {
  switch (ast._tag) {
    case "Transformation":
      return unwrapAST(ast.to)
    case "Refinement":
      return unwrapAST(ast.from)
    case "Suspend":
      return unwrapAST(ast.f())
    default:
      return ast
  }
}

const getTag = (ast: AST.AST): string | undefined => {
  const unwrapped = unwrapAST(ast)
  if (unwrapped._tag === "TypeLiteral") {
    const ps = unwrapped.propertySignatures.find((ps) => ps.name === "_tag")
    if (ps !== undefined) {
      const type = unwrapAST(ps.type)
      if (type._tag === "Literal" && typeof type.literal === "string") {
        return type.literal
      }
    }
  } else if (ast._tag === "Transformation") {
    // e.g. `Schema.TaggedClass` keeps the `_tag` on the `from` struct
    return getTag(ast.from)
  }
  return undefined
}

/**
 * Extract the `_tag` of each member of a tagged union schema.
 *
 * Returns `undefined` when the schema is not a union, or when any member is
 * missing a string literal `_tag`. Supports `Schema.TaggedClass` as well as
 * wrapped (including transformed) or suspended union members.
 *
 * @since 1.0.0
 * @category reflection
 */
export const extractUnionTags = (ast: AST.AST): ReadonlyArray<string> | undefined => {
  const unwrapped = unwrapAST(ast)
  if (!AST.isUnion(unwrapped)) {
    return undefined
  }
  const tags: Array<string> = []
  for (const member of unwrapped.types) {
    const tag = getTag(member)
    if (tag === undefined) {
      return undefined
    }
    tags.push(tag)
  }
  return tags
}

/**
 * Create an encoder that JSON-encodes a value using `schema` and formats it as
 * a data-only SSE message.
