export const makeEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): (data: string) => Effect.Effect<A, ParseError, R> => {
  const decode = Schema.decodeUnknown(Schema.parseJson(schema))
  return (data) => decode(data)
}

/**
